var ship = createSprite(200, 360);
ship.setAnimation("ship");
var poop = createSprite(190, 93);
poop.setAnimation("poop");
var bullet = createSprite(200, 350);
bullet.setAnimation("bullet");
var alien = createSprite(40, 25);
alien.setAnimation("alien");
poop.visible = 0;
poop.scale = 0.2;
ship.scale = 0.2;
alien.scale = 0.10;
bullet.visible = 0;
var score = 0;
var ballon = createSprite(200, 120);
ballon.setAnimation("ballon");
ballon.visible = 0;
ballon.scale = 0.5;
alien.velocityX = 3;

function draw() {
  background("skyblue");
  if (400 < ship.x) {
    ship.x = 38;
  }
  if (ship.x < 0) {
    ship.x = 380;
  }
  if (alien.x > 360) {
    alien.y = alien.y + 20;
    alien.velocityX = -4;
  }
  if (40 > alien.x) {
    alien.y = alien.y + 20;
    alien.velocityX = 4;
  }

  if (keyWentDown("space") && bullet.visible == 0) {
    bullet.x = ship.x;
    bullet.y = ship.y - 45;
    bullet.visible = 1;
    bullet.velocityY = -10;
  }

  if (bullet.y < 0) {
    bullet.visible = 0;
    bullet.velocityY = 0;
  }


  if (keyDown("right")) {
    ship.x = ship.x + 4;
  }

  if (keyDown("left")) {
    ship.x = ship.x - 4;
  }

  if (alien.y > 180) {
    background("black");
    fill("red");
    textSize(20);
    text("you lose", 185, 200);
    poop.visible = 1;
    alien.visible = 0;
    ship.visible = 0;
  }

  line(0, 200, 400, 200);
  text("use arrow keys to move and dont let the alien cross the black line", 40, 312);
  if (bullet.isTouching(alien)) {
    score = score + 1;
  }
  if (bullet.isTouching(alien)) {
    alien.x = 40;
    alien.y = 10;
    bullet.visible = 0;
    bullet.velocityY = 0;
    bullet.y = 500;
  }
  text(score, 220, 260);
  text("score:", 170, 260);
  if (score > 10) {
    background("skyblue");
    ballon.visible = 1;
    text("you win", 180, 270);
    alien.visible = 0;
    ship.visible = 0;
  }

  drawSprites();
}
